////  OnlineGameViewModel.swift//  imposterFinalProject////  Created by admin on 5/3/26.//import Foundationimport FirebaseAuthimport Combine@MainActorclass OnlineGameViewModel: ObservableObject {        let gameService: GameService    let chatService: ChatService        @Published var gameId: String    @Published var discussionTimeLeft: Int = 180    @Published var myVote: String?    @Published var errorMessage: String?    @Published var isLoading: Bool = false    @Published var currentStatus: Game.GameStatus = .lobby  // ← add this        private var timer: Timer?    private var statusObserver: AnyCancellable?  // ← add this        init(gameId: String, gameService: GameService) {        self.gameId = gameId        self.gameService = gameService        self.chatService = ChatService()                // ← Watch gameService.game changes and mirror status        statusObserver = gameService.$game            .receive(on: DispatchQueue.main)            .sink { [weak self] game in                print("🔄 VM saw status: \(game.status)")                self?.currentStatus = game.status            }    }        // Lifecycle    func onAppear() {        print("🔄 OnlineGameViewModel onAppear")        chatService.startListening(gameId: gameId)        gameService.listenToGame(gameId: gameId)                    // Set initial status        currentStatus = gameService.game.status        print("🔄 Initial status: \(currentStatus)")    }    func onDisappear() {        gameService.stopListening()        chatService.stopListening()        timer?.invalidate()    }        // Discussion Timer    func startDiscussionTimer() {        discussionTimeLeft = 180        timer?.invalidate()        timer = Timer.scheduledTimer(            withTimeInterval: 1,            repeats: true        ) { [weak self] _ in            guard let self else { return }            Task { @MainActor in                if self.discussionTimeLeft > 0 {                    self.discussionTimeLeft -= 1                } else {                    self.timer?.invalidate()                    try? await self.moveToVoting()                }            }        }    }        // Game Actions    func startGame() async throws {        isLoading = true        defer { isLoading = false }        try await gameService.startGame(gameId: gameId)        try await chatService.sendSystemMessage(            gameId: gameId,            text: "🎮 Game started! Discuss and find the impostor."        )    }        func moveToVoting() async throws {        timer?.invalidate()        print("🔄 Updating status to voting in Firestore...")        try await gameService.moveToVoting(gameId: gameId)        print("✅ Status updated to voting")        try await chatService.sendSystemMessage(            gameId: gameId,            text: "🗳️ Discussion over — time to vote!"        )    }        func castVote(for targetId: String) async throws {        guard myVote == nil else { return }        myVote = targetId        try await gameService.castVote(            gameId: gameId,            targetId: targetId        )        if gameService.allVotesCast {            try await resolveVotes()        }    }        func resolveVotes() async throws {        let impostorName = gameService.players            .first { $0.id == gameService.game.impostorId }?            .name ?? "Unknown"                try await gameService.resolveVotes(gameId: gameId)                let wasImpostorEliminated = gameService.game.status == .ended                try await chatService.sendSystemMessage(            gameId: gameId,            text: wasImpostorEliminated                ? "✅ \(impostorName) was the impostor! Crew wins!"                : "❌ The impostor survives..."        )    }        // Convenience Passthroughs    var game: Game { gameService.game }    var players: [Player] { gameService.players }    var alivePlayers: [Player] { gameService.alivePlayers }    var isHost: Bool { gameService.isHost }    var currentPlayer: Player? { gameService.currentPlayer }    var messages: [ChatMessage] { chatService.messages }    var allVotesCast: Bool { gameService.allVotesCast }    var voteCounts: [String: Int] { gameService.voteCounts }        var currentPlayerIsImpostor: Bool {        currentPlayer?.isImpostor ?? false    }        var currentPlayerWord: String {        currentPlayer?.vote ?? ""    }}